def sieve_of_eratosthenes(n):
    if n< 2:
        return []

    primes = [True] * (n + 1)
    primes[0] = primes[1] = False

    for p in range(2, int(n**0.5) + 1):
        if primes[p]:
            for i in range(p * p, n + 1, p):
                primes[i] = False

    return [p for p, is_prime in enumerate(primes) if is_prime]
